using namespace std;

class Solution {
public:
    long long minimumSteps(string s) {
        int n = s.size();
        vector<int> rightZero(n + 1, 0);
        for (int i = n - 1; i >= 0; --i) {
            rightZero[i] = rightZero[i + 1] + (s[i] == '0');
        }
        long long res = 0;
        for (int i = 0; i < n; ++i) {
            if (s[i] == '1') {
                res += rightZero[i + 1];
            }
        }
        return res;
    }
};

